apt-get update && apt-get install -y python3 python3-pip rustc cargo
    pip3 install pytest numpy

    mkdir -p /home/user
    cd /home/user

    cat << 'EOF' > /home/user/generate_data.py
import numpy as np

np.random.seed(42)

# Raw data: say, normal distribution shifted
raw_data = np.random.normal(loc=2.0, scale=1.5, size=500)

# Target/Reference data: generated by transforming with alpha=0.35, beta=0.8
# and adding some noise to make the exact KS test non-zero
ref_data = 0.35 * (raw_data ** 2) + 0.8 * raw_data + np.random.normal(0, 0.1, size=500)

with open('/home/user/raw_data.csv', 'w') as f:
    f.write("x\n")
    for val in raw_data:
        f.write(f"{val}\n")

with open('/home/user/ref_data.csv', 'w') as f:
    f.write("z\n")
    for val in ref_data:
        f.write(f"{val}\n")
EOF

    python3 /home/user/generate_data.py
    rm /home/user/generate_data.py

    useradd -m -s /bin/bash user || true
    chmod -R 777 /home/user